+    expect(uniq.size).toBe(8);
+    const edgeUse = new Map<string, number>();
+    for (let t = 0; t < triIndex.length; t += 3) {
+      const k = [
+        posKey(positions, triIndex[t]!),
+        posKey(positions, triIndex[t + 1]!),
+        posKey(positions, triIndex[t + 2]!),
