export type Solid = {
  vertices: Map<TopoId, Vertex>;
  halfEdges: Map<TopoId, HalfEdge>;
  edges: Map<TopoId, Edge>;
  loops: Map<TopoId, BLoop>;
  faces: Map<TopoId, Face>;
