+// 2 * signed area of triangle (a,b,c); positive = CCW
+function twiceArea(a: Vec2, b: Vec2, c: Vec2): number {
+  return cross2(sub2(b, a), sub2(c, a));
+}
+
+describe('earClip', () => {
+  it('triangulates a CCW 4x3 rectangle into 2 CCW triangles, area 12', () => {
+    const pts: Vec2[] = [
