+  // as inside (>= -EPS_L): clipping an ear whose edge passes through another
+  // vertex would create a T-junction.
+  for (const j of idx) {
+    if (j === i0 || j === i1 || j === i2) continue;
+    if (pointInTriInclusive(pts[j]!, a, b, c)) return false;
+  }
