+    mesh: {
+      positions: Float32Array.from(positions),
+      normals: Float32Array.from(normals),
+      triIndex: Uint32Array.from(triIndex),
+      faceSpans,
+    },
+    edges: {
+      positions: Float32Array.from(edgePositions),
+      edgeSpans,
+    },
+  };
+}"}

