    let clipped = false;
    for (let i = 0; i < idx.length; i++) {
      const i0 = idx[(i + idx.length - 1) % idx.length]!; // `!`: noUncheckedIndexedAccess
      const i1 = idx[i]!;
      const i2 = idx[(i + 1) % idx.length]!;
      if (isEar(pts, idx, i0, i1, i2)) {
